/**
 * Notification log model — tracks sent notifications for history/audit purposes.
 *
 * Each log entry captures who received the notification, through which channel,
 * what type it was, when it was sent, and whether delivery succeeded.
 */

import type { NotificationChannel, NotificationType, NotificationStatus } from './notification.js';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  notificationType: NotificationType;
  status: NotificationStatus;
  subject: string;
  body: string;
  timestamp: Date;
  metadata?: Record<string, unknown>;
}

export interface NotificationHistoryQuery {
  userId?: string;
  recipient?: string;
  notificationType?: NotificationType;
  channel?: NotificationChannel;
  status?: NotificationStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType, NotificationStatus } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      notificationType: record['notificationType'] as NotificationType,
      status: record['status'] as NotificationStatus,
      subject: record['subject'] as string,
      body: record['body'] as string,
      timestamp: new Date(record['timestamp'] as string),
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) as Record<string, unknown> : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      notificationType: entity.notificationType,
      status: entity.status,
      subject: entity.subject,
      body: entity.body,
      timestamp: entity.timestamp.toISOString(),
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : undefined,
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByUserId(userId: string): NotificationLog[] {
    return this.findAll((log) => log.metadata?.userId === userId);
  }

  findByNotificationType(notificationType: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.notificationType === notificationType);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.timestamp >= startDate && log.timestamp <= endDate,
    );
  }
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * Integrates with NotificationService to automatically log every
 * notification that is sent. Provides query methods to retrieve
 * notification history by user, type, date range, etc.
 */

import type { Notification } from '../models/notification.js';
import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset the log ID counter. For testing only. */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a sent notification. Called by NotificationService after sending.
   */
  logNotification(notification: Notification): NotificationLog {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      notificationType: notification.notificationType,
      status: notification.status,
      subject: notification.subject,
      body: notification.body,
      timestamp: notification.sentAt,
      metadata: notification.metadata,
    };

    this.repository.save(log);
    this.logger.info(`Logged notification ${notification.id} (${notification.status})`);
    return log;
  }

  /**
   * Query notification history with flexible filters.
   */
  query(query: NotificationHistoryQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (query.userId && log.metadata?.userId !== query.userId) return false;
      if (query.recipient && log.recipient !== query.recipient) return false;
      if (query.notificationType && log.notificationType !== query.notificationType) return false;
      if (query.channel && log.channel !== query.channel) return false;
      if (query.status && log.status !== query.status) return false;
      if (query.startDate && log.timestamp < query.startDate) return false;
      if (query.endDate && log.timestamp > query.endDate) return false;
      return true;
    });
  }

  /**
   * Get all history entries for a recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all history entries for a user (by userId in metadata).
   */
  getByUserId(userId: string): NotificationLog[] {
    return this.repository.findByUserId(userId);
  }

  /**
   * Get all history entries for a notification type.
   */
  getByType(notificationType: NotificationLog['notificationType']): NotificationLog[] {
    return this.repository.findByNotificationType(notificationType);
  }

  /**
   * Get all history entries within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get total count of logged notifications.
   */
  getCount(): number {
    return this.repository.count();
  }
}

