import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body',
    channel: 'email',
    notificationType: 'order_confirmation',
    status: 'sent',
    sentAt: new Date('2026-01-15T10:00:00Z'),
    metadata: { userId: 'user-1' },
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a notification and return the log entry', () => {
      const notification = makeNotification();
      const log = historyService.logNotification(notification);

      expect(log.id).toBe('nlog-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.notificationType).toBe('order_confirmation');
      expect(log.status).toBe('sent');
      expect(log.subject).toBe('Test Subject');
      expect(log.body).toBe('Test body');
      expect(log.timestamp).toEqual(new Date('2026-01-15T10:00:00Z'));
      expect(log.metadata).toEqual({ userId: 'user-1' });
    });

    it('should generate sequential log IDs', () => {
      const log1 = historyService.logNotification(makeNotification({ id: 'notif-0001' }));
      const log2 = historyService.logNotification(makeNotification({ id: 'notif-0002' }));

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
    });

    it('should persist to the repository', () => {
      historyService.logNotification(makeNotification());
      expect(repository.count()).toBe(1);
    });

    it('should log failed notifications', () => {
      const log = historyService.logNotification(makeNotification({ status: 'failed' }));
      expect(log.status).toBe('failed');
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.logNotification(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          notificationType: 'order_confirmation',
          channel: 'email',
          status: 'sent',
          sentAt: new Date('2026-01-15T10:00:00Z'),
          metadata: { userId: 'user-1' },
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          notificationType: 'order_status_update',
          channel: 'webhook',
          status: 'failed',
          sentAt: new Date('2026-01-16T10:00:00Z'),
          metadata: { userId: 'user-2' },
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          notificationType: 'welcome',
          channel: 'email',
          status: 'sent',
          sentAt: new Date('2026-01-17T10:00:00Z'),
          metadata: { userId: 'user-1' },
        }),
      );
    });

    it('should filter by userId', () => {
      const results = historyService.query({ userId: 'user-1' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.metadata?.userId === 'user-1')).toBe(true);
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'bob@example.com' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should filter by notification type', () => {
      const results = historyService.query({ notificationType: 'order_confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationType).toBe('order_confirmation');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-01-15T00:00:00Z'),
        endDate: new Date('2026-01-16T23:59:59Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        userId: 'user-1',
        channel: 'email',
        notificationType: 'order_confirmation',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0001');
    });

    it('should return all entries when no filters provided', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });
  });

  describe('convenience query methods', () => {
    beforeEach(() => {
      historyService.logNotification(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          metadata: { userId: 'user-1' },
        }),
      );
      historyService.logNotification(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          notificationType: 'order_status_update',
          sentAt: new Date('2026-02-01T10:00:00Z'),
          metadata: { userId: 'user-2' },
        }),
      );
    });

    it('should get by recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('unknown@example.com')).toHaveLength(0);
    });

    it('should get by userId', () => {
      expect(historyService.getByUserId('user-1')).toHaveLength(1);
      expect(historyService.getByUserId('user-99')).toHaveLength(0);
    });

    it('should get by type', () => {
      expect(historyService.getByType('order_confirmation')).toHaveLength(1);
      expect(historyService.getByType('order_status_update')).toHaveLength(1);
      expect(historyService.getByType('welcome')).toHaveLength(0);
    });

    it('should get by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-01-01T00:00:00Z'),
        new Date('2026-01-31T23:59:59Z'),
      );
      expect(results).toHaveLength(1);
    });

    it('should return total count', () => {
      expect(historyService.getCount()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications when events are emitted', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getCount()).toBe(1);
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationType).toBe('order_confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.channel).toBe('email');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } as OrderStatusChangedEvent);

      expect(historyService.getCount()).toBe(2);
      const byType = historyService.getByType('order_status_update');
      expect(byType).toHaveLength(1);
    });

    it('should capture userId in history metadata', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-42',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-42',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } as OrderCreatedEvent);

      const logs = historyService.getByUserId('user-42');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.recipient).toBe('bob@example.com');
    });
  });
});
